// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Alert
// shadcn/ui-aligned API: forwardRef, variant, cva, compound parts.
// Banner-style status component for inline messages, errors,
// system notices, etc. Variants: default | accent | warning | fault.
//
//   <Alert variant="fault">
//     <AlertIcon><AlertOctagon /></AlertIcon>
//     <AlertContent>
//       <AlertTitle>Telemetry lost</AlertTitle>
//       <AlertDescription>Reconnecting to vehicle…</AlertDescription>
//     </AlertContent>
//   </Alert>
// ============================================================

'use client';

import { forwardRef } from 'react';
import { cva } from 'class-variance-authority';
import { cn, andromedaVars } from './lib/utils';

const alertVariants = cva(
  [
    'relative flex items-start gap-[var(--andromeda-3)]',
    'p-[var(--andromeda-3)]',
    'border border-solid',
    'rounded-[var(--andromeda-radius-none)]',
    '[backdrop-filter:blur(2px)] [-webkit-backdrop-filter:blur(2px)]',
  ],
  {
    variants: {
      variant: {
        default: [
          'bg-[color:var(--andromeda-surface-raised)]',
          'border-[color:var(--andromeda-border-base)]',
          '[--alert-icon-color:var(--andromeda-text-secondary)]',
          '[--alert-title-color:var(--andromeda-text-primary)]',
          '[--alert-description-color:var(--andromeda-text-secondary)]',
        ],
        accent: [
          // title 6.2:1 / description 5.1:1 on bg-500 (WCAG AA pass)
          'bg-[color:var(--andromeda-accent-500)]',
          'border-[color:var(--andromeda-accent-400)]',
          '[--alert-icon-color:var(--andromeda-accent-300)]',
          '[--alert-title-color:var(--andromeda-accent-100)]',
          '[--alert-description-color:var(--andromeda-accent-200)]',
        ],
        warning: [
          // title 9.2:1 / description 6.2:1 on bg-500 (WCAG AA pass)
          'bg-[color:var(--andromeda-orange-500)]',
          'border-[color:var(--andromeda-orange-400)]',
          '[--alert-icon-color:var(--andromeda-orange-300)]',
          '[--alert-title-color:var(--andromeda-orange-100)]',
          '[--alert-description-color:var(--andromeda-orange-200)]',
        ],
        fault: [
          // title 9.6:1 / description 6.0:1 on bg-500 (WCAG AA pass)
          'bg-[color:var(--andromeda-red-500)]',
          'border-[color:var(--andromeda-red-400)]',
          '[--alert-icon-color:var(--andromeda-red-300)]',
          '[--alert-title-color:var(--andromeda-red-100)]',
          '[--alert-description-color:var(--andromeda-red-200)]',
        ],
      },
    },
    defaultVariants: { variant: 'default' },
  },
);

/**
 * @typedef {object} AlertProps
 * @property {'default'|'accent'|'warning'|'fault'} [variant='default']
 * @property {React.ReactNode} [children]
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<AlertProps & React.HTMLAttributes<HTMLDivElement>>} */
export const Alert = forwardRef(function Alert(
  { className, variant = 'default', children, style, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      role="alert"
      data-slot="alert"
      className={cn(alertVariants({ variant }), className)}
      style={{ ...andromedaVars(), ...style }}
      {...props}
    >
      {children}
    </div>
  );
});

/** Icon slot — recolors any child SVG to the variant's icon color. */
export const AlertIcon = forwardRef(function AlertIcon(
  { className, children, ...props },
  ref,
) {
  return (
    <span
      ref={ref}
      data-slot="alert-icon"
      aria-hidden="true"
      className={cn(
        'flex shrink-0 items-center justify-center mt-[1px]',
        '[&>svg]:w-[16px] [&>svg]:h-[16px]',
        'text-[color:var(--alert-icon-color)] [&>svg]:stroke-current',
        className,
      )}
      {...props}
    >
      {children}
    </span>
  );
});

export const AlertContent = forwardRef(function AlertContent(
  { className, children, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="alert-content"
      className={cn('flex flex-col gap-[2px] min-w-0', className)}
      {...props}
    >
      {children}
    </div>
  );
});

export const AlertTitle = forwardRef(function AlertTitle(
  { className, children, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="alert-title"
      className={cn(
        '[font-family:var(--andromeda-font-mono)]',
        'text-[length:var(--andromeda-text-sm)]',
        'font-[number:var(--andromeda-weight-medium)]',
        'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
        'text-[color:var(--alert-title-color)]',
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
});

export const AlertDescription = forwardRef(function AlertDescription(
  { className, children, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="alert-description"
      className={cn(
        '[font-family:var(--andromeda-font-mono)]',
        'text-[length:var(--andromeda-text-xs)]',
        'text-[color:var(--alert-description-color)]',
        'uppercase [letter-spacing:var(--andromeda-tracking-wide)]',
        'leading-[1.6]',
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
});

export { alertVariants };

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Avatar
// shadcn/ui-aligned API: variant/size, cva, forwardRef.
// Sizes: sm | md | lg
// Initials, monospace, square (radius.none).
// Optional status dot: online | caution | fault | offline
// ============================================================

'use client';

import { forwardRef } from 'react';
import { cva } from 'class-variance-authority';
import { cn, andromedaVars } from './lib/utils';

const avatarVariants = cva(
  [
    'inline-flex items-center justify-center select-none shrink-0',
    'border border-solid',
    'rounded-[var(--andromeda-radius-none)]',
    'bg-[color:var(--andromeda-surface-overlay)]',
    'border-[color:var(--andromeda-border-base)]',
    'text-[color:var(--andromeda-text-primary)]',
    '[font-family:var(--andromeda-font-mono)]',
    'font-[number:var(--andromeda-weight-semibold)]',
    '[letter-spacing:var(--andromeda-tracking-normal)]',
    'transition-transform duration-150 ease-out',
    'hover:scale-[1.05]',
  ],
  {
    variants: {
      size: {
        sm: 'w-[24px] h-[24px] text-[length:var(--andromeda-text-xs)]',
        md: 'w-[32px] h-[32px] text-[length:var(--andromeda-text-sm)]',
        lg: 'w-[40px] h-[40px] text-[length:var(--andromeda-text-md)]',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  },
);

const statusDotVariants = cva(
  [
    'absolute -right-[2px] block w-[2px]',
    'top-[15%] h-[70%]',
    'border-0',
  ],
  {
    variants: {
      size: {
        sm: '',
        md: '',
        lg: '',
      },
      status: {
        online:  'bg-[color:var(--andromeda-accent-400)] shadow-[-3px_0_8px_var(--andromeda-accent-500)]',
        caution: 'bg-[color:var(--andromeda-orange-400)] shadow-[-3px_0_8px_var(--andromeda-orange-400)]',
        fault:   'bg-[color:var(--andromeda-red-400)] shadow-[-3px_0_8px_var(--andromeda-red-400)]',
        offline: 'bg-[color:var(--andromeda-text-faint)]',
      },
    },
    defaultVariants: {
      size: 'md',
      status: 'offline',
    },
  },
);

function deriveInitials(name) {
  if (!name) return '?';
  return name
    .split(' ')
    .map((part) => part[0])
    .filter(Boolean)
    .slice(0, 2)
    .join('')
    .toUpperCase();
}

/**
 * @typedef {object} AvatarProps
 * @property {string} [name='?'] Used to derive uppercase initials (shown when no src).
 * @property {string} [src] Optional image URL. When provided, renders an img instead of initials.
 * @property {'sm'|'md'|'lg'} [size='md']
 * @property {'online'|'caution'|'fault'|'offline'} [status] When set, renders a status dot.
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<AvatarProps & React.HTMLAttributes<HTMLDivElement>>} */
export const Avatar = forwardRef(function Avatar(
  { className, name = '?', src, size = 'md', status, style, ...props },
  ref,
) {
  const initials = deriveInitials(name);

  return (
    <div
      ref={ref}
      className="relative inline-flex shrink-0"
      style={{ ...andromedaVars(), ...style }}
      {...props}
    >
      <div className={cn(avatarVariants({ size }), className)}>
        {src
          ? <img src={src} alt={name} style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
          : initials
        }
      </div>
      {status ? <span className={statusDotVariants({ size, status })} aria-hidden="true" /> : null}
    </div>
  );
});

export { avatarVariants, statusDotVariants };

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Badge
// shadcn/ui-aligned API: variant prop, cva, forwardRef.
// Variants: default | accent | warning | fault | subtle | outline
// Monospace, uppercase, wide letter-spacing, sharp corners.
// ============================================================

// ============================================================
// COMPONENT: Badge
// shadcn/ui-aligned API: variant prop, cva, forwardRef.
// Variants: default | accent | warning | fault | subtle | outline
// No border — badge is a read-only status label, not a control.
// Leading 4×4 dot colored by variant distinguishes it from Button.
// ============================================================

'use client';

import { forwardRef, useEffect, useRef, useState } from 'react';
import { cva } from 'class-variance-authority';
import { cn, andromedaVars } from './lib/utils';

// Blinks once every ~2s: full opacity → 0.12 for 200ms → full opacity.
function useBlink() {
  const [opacity, setOpacity] = useState(1);
  const timerRef = useRef(null);

  useEffect(() => {
    function schedule() {
      timerRef.current = setTimeout(() => {
        setOpacity(0.12);
        setTimeout(() => {
          setOpacity(1);
          schedule();
        }, 200);
      }, 1800 + Math.random() * 800);
    }
    schedule();
    return () => clearTimeout(timerRef.current);
  }, []);

  return opacity;
}

const badgeVariants = cva(
  [
    'inline-flex items-center gap-[5px] select-none whiteandromeda-nowrap',
    'rounded-[var(--andromeda-radius-none)]',
    'px-[var(--andromeda-2)] py-[2px]',
    '[font-family:var(--andromeda-font-mono)]',
    'text-[length:var(--andromeda-text-xs)]',
    'font-[number:var(--andromeda-weight-medium)]',
    'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
    '[line-height:var(--andromeda-leading-normal)]',
  ],
  {
    variants: {
      variant: {
        default: [
          'bg-[color:var(--andromeda-surface-active)]',
          'text-[color:var(--andromeda-text-secondary)]',
        ],
        accent: [
          'bg-[color:var(--andromeda-accent-500)]',
          'text-[color:var(--andromeda-text-primary)]',
        ],
        warning: [
          'bg-[color:var(--andromeda-orange-500)]',
          'text-[color:var(--andromeda-text-primary)]',
        ],
        fault: [
          'bg-[color:var(--andromeda-red-500)]',
          'text-[color:var(--andromeda-text-primary)]',
        ],
        subtle: [
          'bg-[color:var(--andromeda-surface-overlay)]',
          'text-[color:var(--andromeda-text-muted)]',
        ],
        outline: [
          'bg-transparent',
          'border border-solid border-[color:var(--andromeda-border-bright)]',
          'text-[color:var(--andromeda-text-primary)]',
        ],
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  },
);

// Dot color per variant — matches the text color of each variant.
const dotColor = {
  default: 'var(--andromeda-text-muted)',
  accent:  'var(--andromeda-accent-300)',
  warning: 'var(--andromeda-orange-300)',
  fault:   'var(--andromeda-red-300)',
  subtle:  'var(--andromeda-text-faint)',
  outline: 'var(--andromeda-text-primary)',
};

/**
 * @typedef {object} BadgeProps
 * @property {'default'|'accent'|'warning'|'fault'|'subtle'|'outline'} [variant='default']
 * @property {React.ReactNode} [children]
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<BadgeProps & React.HTMLAttributes<HTMLSpanElement>>} */
export const Badge = forwardRef(function Badge(
  { className, variant = 'default', children, style, ...props },
  ref,
) {
  const dotOpacity = useBlink();

  return (
    <span
      ref={ref}
      className={cn(badgeVariants({ variant }), className)}
      style={{ ...andromedaVars(), ...style }}
      {...props}
    >
      <span
        aria-hidden="true"
        style={{
          display: 'inline-block',
          width: '4px',
          height: '4px',
          flexShrink: 0,
          background: dotColor[variant ?? 'default'],
          opacity: dotOpacity,
          transition: 'opacity 80ms ease-out',
        }}
      />
      {children}
    </span>
  );
});

export { badgeVariants };

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Button
// shadcn/ui-aligned API: variant, size, asChild, forwardRef.
// Variants: default | outline | ghost | destructive | link
// Sizes:    sm | md | lg
// All interactive states (hover, focus-visible, active, disabled)
// are expressed as cva variants and trace back to Andromeda tokens
// via CSS custom properties from `andromedaVars()`.
// ============================================================

'use client';

import { forwardRef } from 'react';
import { Slot } from '@radix-ui/react-slot';
import { motion } from 'framer-motion';
import { cva } from 'class-variance-authority';
import { cn, andromedaVars } from './lib/utils';
import { useReducedMotion } from './lib/motion';
import { tokens } from '../tokens';

// Token-driven framer transitions. tokens.motion.duration values are
// strings like "140ms"; framer expects seconds, so parseInt → /1000.
const ms = (v) => parseInt(v, 10) / 1000;
const HOVER_TX = { duration: ms(tokens.motion.duration.normal), ease: [0, 0, 0.2, 1] };
const PRESS_TX = { duration: ms(tokens.motion.duration.fast),   ease: [0.4, 0, 1, 1] };
// whileHover / whileTap targets — transitions inlined inside the variant
// so hover uses duration.normal and press uses duration.fast independently.
const HOVER_LIFT = { y: -1, filter: 'brightness(1.05)', transition: HOVER_TX };
const PRESS_DOWN = { scale: 0.98, transition: PRESS_TX };

const buttonVariants = cva(
  [
    // structural
    'relative inline-flex items-center justify-center select-none whiteandromeda-nowrap',
    'gap-[var(--andromeda-2)]',
    'border border-solid',
    'rounded-[var(--andromeda-radius-none)]',
    // typography (all token-driven via CSS vars)
    '[font-family:var(--andromeda-font-mono)]',
    'font-[number:var(--andromeda-weight-medium)]',
    'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
    '[line-height:var(--andromeda-leading-tight)]',
    // motion — colours/border/shadow tween via CSS at duration.normal so the
    // focus ring fades in (was previously a hard snap). Transform/lift/press
    // are driven by framer-motion's whileHover/whileTap on the motion.button
    // root, see below — they get duration.normal (hover) and duration.fast
    // (press) per `tokens.motion`.
    'cursor-pointer',
    'transition-[background-color,border-color,box-shadow,color] [transition-duration:var(--andromeda-duration-normal)] [transition-timing-function:var(--andromeda-easing-out)]',
    '[backdrop-filter:blur(2px)] [-webkit-backdrop-filter:blur(2px)]',
    // focus & disabled
    'focus-visible:outline-none',
    'focus-visible:shadow-[0_0_0_1px_var(--andromeda-accent-400),0_0_8px_var(--andromeda-accent-500)]',
    'disabled:cursor-not-allowed disabled:opacity-[0.35] disabled:pointer-events-none',
  ],
  {
    variants: {
      variant: {
        default: [
          'text-[color:var(--andromeda-text-primary)]',
          'bg-[color:var(--andromeda-accent-400)]',
          'border-[color:var(--andromeda-accent-200)]',
          'hover:bg-[color:var(--andromeda-accent-400)]',
          'hover:border-[color:var(--andromeda-accent-200)]',
          'hover:shadow-[0_0_8px_var(--andromeda-accent-400)]',
          'active:bg-[color:var(--andromeda-accent-400)]',
          'active:border-[color:var(--andromeda-accent-200)]',
        ],
        outline: [
          'text-[color:var(--andromeda-text-primary)]',
          'bg-[color:var(--andromeda-surface-raised)]',
          'border-[color:var(--andromeda-border-base)]',
          'hover:bg-[color:var(--andromeda-surface-hover)]',
          'hover:border-[color:var(--andromeda-border-bright)]',
          'active:bg-[color:var(--andromeda-surface-active)]',
        ],
        ghost: [
          'text-[color:var(--andromeda-text-secondary)]',
          'bg-transparent',
          'border-transparent',
          'hover:text-[color:var(--andromeda-text-primary)]',
          'hover:bg-[color:var(--andromeda-surface-raised)]',
          'active:bg-[color:var(--andromeda-surface-hover)]',
        ],
        destructive: [
          'text-[color:var(--andromeda-text-primary)]',
          'bg-[color:var(--andromeda-red-400)]',
          'border-[color:var(--andromeda-red-400)]',
          'hover:bg-[color:var(--andromeda-red-400)]',
          'hover:border-[color:var(--andromeda-red-300)]',
          'hover:shadow-[0_0_8px_var(--andromeda-red-400)]',
          'focus-visible:shadow-[0_0_0_1px_var(--andromeda-red-400),0_0_8px_var(--andromeda-red-400)]',
          'active:bg-[color:var(--andromeda-red-400)]',
        ],
        link: [
          'text-[color:var(--andromeda-text-primary)]',
          'bg-transparent',
          'border-transparent',
          'underline-offset-4 hover:underline',
          'hover:text-[color:var(--andromeda-text-primary)]',
          // link variant has no shadow ring on focus
          'focus-visible:shadow-none',
          'focus-visible:underline',
        ],
      },
      size: {
        sm: 'px-[var(--andromeda-3)] py-[5px] text-[length:var(--andromeda-text-xs)]',
        md: 'px-[var(--andromeda-4)] py-[var(--andromeda-2)] text-[length:var(--andromeda-text-sm)]',
        lg: 'px-[var(--andromeda-5)] py-[11px] text-[length:var(--andromeda-text-md)]',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'md',
    },
  },
);

/**
 * @typedef {object} ButtonProps
 * @property {'default'|'outline'|'ghost'|'destructive'|'link'} [variant='default']
 * @property {'sm'|'md'|'lg'} [size='md']
 * @property {boolean} [asChild=false]  When true, renders the only child element with the button's props/styles.
 * @property {React.ComponentType<{ size?: number }>} [icon] Phosphor / Lucide icon component rendered before children.
 * @property {React.ReactNode} [children]
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 * @property {boolean} [disabled]
 * @property {(e: React.MouseEvent<HTMLButtonElement>) => void} [onClick]
 */

/** @type {React.ForwardRefExoticComponent<ButtonProps & React.ButtonHTMLAttributes<HTMLButtonElement>>} */
export const Button = forwardRef(function Button(
  {
    className,
    variant = 'default',
    size = 'md',
    asChild = false,
    icon: Icon,
    children,
    style,
    type = 'button',
    disabled,
    ...props
  },
  ref,
) {
  // Icons render ~1.3× the label size so they read clearly next to the text.
  const iconSize = size === 'sm' ? 16 : size === 'md' ? 18 : 20;
  const reducedMotion = useReducedMotion();
  const baseClass = cn(buttonVariants({ variant, size }), className);
  const baseStyle = { ...andromedaVars(), ...style };
  const content = (
    <>
      {Icon ? <Icon size={iconSize} weight="light" /> : null}
      {children}
    </>
  );

  // asChild path — Slot composes onto whatever child was passed (typically
  // an <a>). Slot can't accept framer-motion gesture props, so the asChild
  // path falls back to CSS-only transitions defined in cva. The hover lift
  // + press scale are skipped for this path; this is a known trade-off.
  if (asChild) {
    return (
      <Slot ref={ref} className={baseClass} style={baseStyle} {...props}>
        {content}
      </Slot>
    );
  }

  return (
    <motion.button
      ref={ref}
      type={type}
      className={baseClass}
      style={baseStyle}
      disabled={disabled}
      whileHover={reducedMotion || disabled ? undefined : HOVER_LIFT}
      whileTap={reducedMotion || disabled ? undefined : PRESS_DOWN}
      {...props}
    >
      {content}
    </motion.button>
  );
});

export { buttonVariants };

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Card
// shadcn/ui-aligned compound component:
//   <Card><CardHeader/><CardContent/><CardFooter/></Card>
// Variant: default | glow (adds accent.shade2 tint + bright markers)
// Sharp corners, surface.raised background, thin border.subtle.
// ============================================================

'use client';

import { forwardRef } from 'react';
import { cva } from 'class-variance-authority';
import { cn, andromedaVars } from './lib/utils';
import { CornerMarkers } from './CornerMarkers';

const cardVariants = cva(
  [
    'relative block',
    'rounded-[var(--andromeda-radius-none)]',
    '[backdrop-filter:blur(2px)] [-webkit-backdrop-filter:blur(2px)]',
  ],
  {
    variants: {
      variant: {
        default: ['bg-[color:var(--andromeda-surface-raised)]'],
        glow:    ['bg-[image:var(--andromeda-gradient-accent-sweep)]'],
      },
      bordered: {
        true:  ['border', 'border-solid'],
        false: [],
      },
    },
    compoundVariants: [
      { variant: 'default', bordered: true, class: 'border-[color:var(--andromeda-border-base)]' },
      // Glow uses accent-500 (matches the gradient peak) so the perimeter
      // blends with the fill instead of fighting it. accent-400 was too bright.
      { variant: 'glow',    bordered: true, class: 'border-[color:var(--andromeda-accent-500)]' },
    ],
    defaultVariants: {
      variant: 'default',
      bordered: false,
    },
  },
);

/**
 * @typedef {object} CardProps
 * @property {'default'|'glow'} [variant='default']
 * @property {boolean} [bordered=false] Toggle a continuous 1px border. Off by default — Andromeda cards rely on corner brackets, not perimeter strokes.
 * @property {boolean} [markers=true] Toggle the corner markers motif.
