// COMPONENT: PanelMenu
// Kebab-trigger overflow menu for panel headers. Trigger is an
// IconButton (size sm, ghost). Menu opens beneath it, supports
// items with optional icons and a single level of submenu (right-
// flyout). Closes on outside click and on Escape.
// ============================================================

'use client';

import { forwardRef, useEffect, useRef, useState } from 'react';
import { CaretRight, DotsThreeVertical } from '@phosphor-icons/react';
import { tokens } from '../tokens';
import { IconButton } from './IconButton';
import { andromedaVars } from './lib/utils';

/**
 * @typedef {object} MenuItem
 * @property {string}   [label]
 * @property {React.ComponentType<{ size?: number, weight?: string }>} [icon]
 * @property {() => void} [onSelect]
 * @property {MenuItem[]} [submenu]
 * @property {boolean}  [selected]
 * @property {boolean}  [destructive]
 * @property {'separator'} [type]
 */

/**
 * @typedef {object} PanelMenuProps
 * @property {MenuItem[]} items
 * @property {'left'|'right'} [align='right']
 * @property {string} [ariaLabel='Panel options']
 * @property {boolean} [defaultOpen=false] Render the menu pre-opened. Useful in
 *   showcases / docs so the consumer can see the menu contents without first
 *   having to click the trigger. Click-outside and Escape still dismiss it.
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

const ITEM_HEIGHT = 26;

function MenuItem({ item, onClose }) {
  const [submenuOpen, setSubmenuOpen] = useState(false);
  const itemRef = useRef(null);
  const closeTimer = useRef(null);

  if (item.type === 'separator') {
    return (
      <div
        aria-hidden="true"
        role="separator"
        style={{
          height: '1px',
          margin: `${tokens.spacing[1]} 0`,
          background: tokens.color.border.base,
        }}
      />
    );
  }

  const Icon = item.icon;
  const hasSub = Array.isArray(item.submenu) && item.submenu.length > 0;

  // Hover-with-grace-period so the user can move the cursor across the gap
  // between the parent item and the submenu without the submenu collapsing.
  function handleEnter() {
    clearTimeout(closeTimer.current);
    if (hasSub) setSubmenuOpen(true);
  }
  function handleLeave() {
    if (hasSub) {
      closeTimer.current = setTimeout(() => setSubmenuOpen(false), 120);
    }
  }

  function handleClick() {
    if (hasSub) {
      setSubmenuOpen((o) => !o);
      return;
    }
    item.onSelect?.();
    onClose();
  }

  const color = item.destructive
    ? tokens.color.red[300]
    : item.selected
      ? tokens.color.text.primary
      : tokens.color.text.secondary;

  return (
    <div
      ref={itemRef}
      onMouseEnter={handleEnter}
      onMouseLeave={handleLeave}
      style={{ position: 'relative' }}
    >
      <button
        type="button"
        role="menuitem"
        aria-haspopup={hasSub ? 'menu' : undefined}
        aria-expanded={hasSub ? submenuOpen : undefined}
        onClick={handleClick}
        className="andromeda-panel-menu-item"
        data-selected={item.selected ? 'true' : 'false'}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: tokens.spacing[2],
          width: '100%',
          height: `${ITEM_HEIGHT}px`,
          padding: `0 ${tokens.spacing[3]}`,
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.sm,
          fontWeight: item.selected ? tokens.typography.weight.medium : tokens.typography.weight.regular,
          color,
          textAlign: 'left',
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.wide,
          whiteSpace: 'nowrap',
          transition: 'background 100ms ease, color 100ms ease',
        }}
      >
        {Icon ? <Icon size={14} weight="regular" /> : <span style={{ width: '14px' }} />}
        <span style={{ flex: 1 }}>{item.label}</span>
        {hasSub ? <CaretRight size={10} weight="bold" /> : null}
      </button>

      {/* Right-flyout submenu */}
      {hasSub && submenuOpen ? (
        <div
          role="menu"
          style={{
            position: 'absolute',
            top: 0,
            left: '100%',
            marginLeft: tokens.spacing[1],
            minWidth: '160px',
            background: tokens.color.surface.overlay,
            border: `${tokens.border.thin} ${tokens.color.border.bright}`,
            padding: tokens.spacing[1],
            zIndex: 1001,
            boxShadow: `0 12px 28px ${tokens.color.surface.alpha}`,
          }}
        >
          {item.submenu.map((sub, i) => (
            <MenuItem key={i} item={sub} onClose={onClose} />
          ))}
        </div>
      ) : null}
    </div>
  );
}

/** @type {React.ForwardRefExoticComponent<PanelMenuProps & React.HTMLAttributes<HTMLDivElement>>} */
export const PanelMenu = forwardRef(function PanelMenu(
  { items, align = 'right', ariaLabel = 'Panel options', defaultOpen = false, className, style, ...props },
  ref,
) {
  const [open, setOpen] = useState(defaultOpen);
  const wrapperRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    function onClick(e) {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target)) {
        setOpen(false);
      }
    }
    function onKey(e) {
      if (e.key === 'Escape') setOpen(false);
    }
    document.addEventListener('mousedown', onClick);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', onClick);
      document.removeEventListener('keydown', onKey);
    };
  }, [open]);

  return (
    <div
      ref={(node) => {
        wrapperRef.current = node;
        if (typeof ref === 'function') ref(node);
        else if (ref) ref.current = node;
      }}
      data-slot="panel-menu"
      className={className}
      style={{ ...andromedaVars(), position: 'relative', display: 'inline-flex', ...style }}
      {...props}
    >
      <IconButton
        aria-label={ariaLabel}
        aria-haspopup="menu"
        aria-expanded={open}
        variant="ghost"
        size="sm"
        icon={DotsThreeVertical}
        onClick={() => setOpen((o) => !o)}
        data-state={open ? 'open' : 'closed'}
        style={open ? {
          background: tokens.color.surface.active,
          color: tokens.color.text.primary,
        } : undefined}
      />

      {open ? (
        <div
          role="menu"
          style={{
            position: 'absolute',
            top: 'calc(100% + 4px)',
            [align === 'right' ? 'right' : 'left']: 0,
            minWidth: '160px',
            background: tokens.color.surface.overlay,
            border: `${tokens.border.thin} ${tokens.color.border.bright}`,
            padding: tokens.spacing[1],
            zIndex: 1000,
            boxShadow: `0 12px 28px ${tokens.color.surface.alpha}`,
          }}
        >
          {items.map((item, i) => (
            <MenuItem key={i} item={item} onClose={() => setOpen(false)} />
          ))}
        </div>
      ) : null}

      <style>{`
        /* !important is required: the menuitem button carries inline
           style={{ background:'transparent', color }} which would otherwise
           beat any class rule on hover/active. Same precedence trap as
           DateRangePicker — see rules.md "Hover on inline-styled controls". */
        .andromeda-panel-menu-item:hover {
          background: ${tokens.color.surface.hover} !important;
          color: ${tokens.color.text.primary} !important;
        }
        .andromeda-panel-menu-item:active {
          background: ${tokens.color.surface.active} !important;
          color: ${tokens.color.text.primary} !important;
        }
        .andromeda-panel-menu-item[data-selected="true"] {
          background: ${tokens.color.surface.active} !important;
          color: ${tokens.color.text.primary} !important;
        }
        .andromeda-panel-menu-item:focus-visible {
          outline: none;
          box-shadow: inset 0 0 0 1px ${tokens.color.accent[400]};
        }
      `}</style>
    </div>
  );
});

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Planet
// Particle-sphere rendered with Three.js — a slowly-rotating
// 3D sphere lit from one side. All particle colors are sourced
// from the Andromeda accent ramp (100 lit → 500 shadow), so the
// component automatically follows the system palette.
//
// Designed for "next destination" / "active body" widgets in the
// mission-control dashboard. The canvas is transparent — drop it
// inside a Card and the void shows through. Resize-observed.
// ============================================================

'use client';

import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { tokens } from '../tokens';

/** Soft radial sprite. Multiplied by vertex color and blended additively
 *  so each particle reads as a tiny glow on the dark void. */
function makeSprite(): THREE.CanvasTexture {
  const size = 64;
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d');
  const half = size / 2;
  const grad = ctx.createRadialGradient(half, half, 0, half, half, half);
  grad.addColorStop(0.00, 'rgba(255,255,255,1.00)');
  grad.addColorStop(0.20, 'rgba(255,255,255,0.78)');
  grad.addColorStop(0.55, 'rgba(255,255,255,0.22)');
  grad.addColorStop(1.00, 'rgba(255,255,255,0.00)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, size, size);
  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  return tex;
}

export function Planet({
  /** Number of surface particles. 6000 reads dense at 320–480px. */
  particleCount = 6000,
  /** Per-particle point size in world units. */
  particleSize = 0.028,
  /** Rotation speed (radians per frame, ~60fps assumed). */
  rotationSpeed = 0.0035,
  /** When true, the planet doesn't auto-rotate. */
  paused = false,
  className,
  style,
}: {
  particleCount?: number;
  particleSize?: number;
  rotationSpeed?: number;
  paused?: boolean;
  className?: string;
  style?: React.CSSProperties;
} = {}) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let W = container.clientWidth  || 320;
    let H = container.clientHeight || 320;

    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(48, W / H, 0.1, 100);
    camera.position.z = 3;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    // Transparent canvas — let the parent (Card / void) show through.
    renderer.setClearColor(0x000000, 0);
    container.appendChild(renderer.domElement);

    // ── Andromeda palette → THREE.Color ─────────────────────────────────────
    const cHi  = new THREE.Color(tokens.color.accent[100]); // lit highlight
    const cLit = new THREE.Color(tokens.color.accent[200]); // lit body
    const cMid = new THREE.Color(tokens.color.accent[400]); // terminator
    const cShd = new THREE.Color(tokens.color.accent[500]); // shadow side

    // Light comes from the front-right, slightly above. Choose a direction
    // that's NOT axis-aligned so the rotating planet shows a moving terminator.
    const lightDir = new THREE.Vector3(0.55, 0.30, 0.78).normalize();

    // ── Buffer geometry: positions + per-vertex colors ──────────────────────
    const positions = new Float32Array(particleCount * 3);
    const colors    = new Float32Array(particleCount * 3);

    for (let i = 0; i < particleCount; i++) {
      // Uniform-on-sphere sampling
      const theta = Math.acos(2 * Math.random() - 1);
      const phi   = 2 * Math.PI * Math.random();
      // Tiny radius jitter so the surface reads as "atmosphere" not a hard shell.
      const r = 1.0 + (Math.random() - 0.5) * 0.06;

      const x = r * Math.sin(theta) * Math.cos(phi);
      const y = r * Math.cos(theta);
      const z = r * Math.sin(theta) * Math.sin(phi);

      positions[i * 3]     = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = z;

      // Lambert-style: dot(normal, lightDir) ∈ [-1, 1] → [0, 1]
      const dot = (x * lightDir.x + y * lightDir.y + z * lightDir.z) / r;
      const lit = (dot + 1) * 0.5;

      // Two-stop ramp: shadow → mid (lit ∈ [0, 0.5]), then mid → lit (lit ∈ [0.5, 1]).
      const c = new THREE.Color();
      if (lit < 0.5) c.lerpColors(cShd, cMid, lit * 2);
      else           c.lerpColors(cMid, cLit, (lit - 0.5) * 2);

      // Equator emphasis — particles near the equator ride a tiny bit brighter,
      // suggesting cloud bands without a literal texture.
      const equator = 1 - Math.abs(y / r) * 0.18;

      // 1% of well-lit particles become highlight specks — adds tiny "city
      // light" / atmospheric sparkle on the lit hemisphere.
      let cr = c.r * equator, cg = c.g * equator, cb = c.b * equator;
      if (Math.random() < 0.012 && lit > 0.62) {
        cr = cHi.r; cg = cHi.g; cb = cHi.b;
      }

      colors[i * 3]     = cr;
      colors[i * 3 + 1] = cg;
      colors[i * 3 + 2] = cb;
    }

    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setAttribute('color',    new THREE.BufferAttribute(colors, 3));

    const sprite = makeSprite();
    const mat = new THREE.PointsMaterial({
      size:         particleSize,
      map:          sprite,
      vertexColors: true,
      transparent:  true,
      depthWrite:   false,
      blending:     THREE.AdditiveBlending,
    });

    const mesh = new THREE.Points(geo, mat);
    mesh.rotation.x = 0.22;
    mesh.rotation.z = 0.06;
    scene.add(mesh);

    // ── Resize handling ─────────────────────────────────────────────────────
    const ro = new ResizeObserver(() => {
      const nw = container.clientWidth  || W;
      const nh = container.clientHeight || H;
      if (nw === W && nh === H) return;
      W = nw; H = nh;
      renderer.setSize(W, H);
      camera.aspect = W / H;
      camera.updateProjectionMatrix();
    });
    ro.observe(container);

    // ── Animation loop ──────────────────────────────────────────────────────
    let raf = 0;
    let t = 0;
    let alive = true;
    function tick() {
      if (!alive) return;
      raf = requestAnimationFrame(tick);
      if (!paused) {
        t += rotationSpeed;
        mesh.rotation.y = t;
        // Gentle Z wobble — keeps the rotation from feeling mechanical.
        mesh.rotation.z = 0.06 + Math.sin(t * 0.4) * 0.035;
      }
      renderer.render(scene, camera);
    }
    tick();

    return () => {
      alive = false;
      cancelAnimationFrame(raf);
      ro.disconnect();
      geo.dispose();
      mat.dispose();
      sprite.dispose();
      renderer.dispose();
      if (container.contains(renderer.domElement)) {
        container.removeChild(renderer.domElement);
      }
    };
  }, [particleCount, particleSize, rotationSpeed, paused]);

  return (
    <div
      ref={containerRef}
      className={className}
      style={{
        width: '100%',
        height: '100%',
        ...style,
      }}
    />
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: ProgressBar
// shadcn/ui-aligned API: variant, forwardRef, ARIA progressbar.
// Variants: default | warning | fault
// Visual: a row of bars, each bar = 3 stacked squares. All bars
// are the same height. Filled bars glow in the variant colour.
// ============================================================

'use client';

import { forwardRef, useEffect, useRef, useState } from 'react';
import { useInView } from 'framer-motion';
import { cn, andromedaVars } from './lib/utils';

const BARS       = 30;  // number of columns
const SQUARES    = 1;   // squares per column
const SQUARE_W   = 6;   // width in px
const SQUARE_H   = 16;  // height in px
const GAP_INNER  = 2;   // gap between squares within a column
const GAP_COL    = 3;   // gap between columns

const variantConfig = {
  default: {
    activeColor:  'var(--andromeda-accent-400)',
    activeBorder: 'var(--andromeda-accent-400)',
  },
  warning: {
    activeColor:  'var(--andromeda-orange-400)',
    activeBorder: 'var(--andromeda-orange-400)',
  },
  fault: {
    activeColor:  'var(--andromeda-red-400)',
    activeBorder: 'var(--andromeda-red-400)',
  },
};

const labelClass = cn(
  '[font-family:var(--andromeda-font-mono)]',
  'text-[length:var(--andromeda-text-xs)]',
  'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
  'text-[color:var(--andromeda-text-secondary)]',
);

const valueClass = cn(
  '[font-family:var(--andromeda-font-mono)]',
  'text-[length:var(--andromeda-text-xs)]',
  'font-[number:var(--andromeda-weight-medium)]',
  'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
  'text-[color:var(--andromeda-text-primary)]',
);

/**
 * @typedef {object} ProgressBarProps
 * @property {string} [label]
 * @property {number} value 0–100; clamped internally.
 * @property {'default'|'warning'|'fault'} [variant='default']
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<ProgressBarProps & React.HTMLAttributes<HTMLDivElement>>} */
export const ProgressBar = forwardRef(function ProgressBar(
  { className, label, value, variant = 'default', style, ...props },
  outerRef,
) {
  const clamped     = Math.max(0, Math.min(100, Number.isFinite(value) ? value : 0));
  const activeCount = Math.round((clamped / 100) * BARS);
  const cfg         = variantConfig[variant] ?? variantConfig.default;

  // Scroll-aware fill: render with zero-active first, then on first
  // viewport intersection switch to `activeCount` so the per-bar
  // transition-delay below lights them up left→right at the moment
  // the user actually sees the bar. ProgressBars below the fold no
  // longer animate invisibly.
  //
  // `once: true` — animate only the first time. Re-entering the
  // viewport (scroll up, scroll down again) doesn't re-trigger.
  // `amount: 0.3` — wait until 30% of the bar is visible. Higher
  // than the cascade's 0.15 because the bar's reveal is its own
  // motion event; we want the user clearly looking at it.
  const internalRef = useRef(null);
  const setRefs = (node) => {
    internalRef.current = node;
    if (typeof outerRef === 'function') outerRef(node);
    else if (outerRef) outerRef.current = node;
  };
  const inView = useInView(internalRef, { once: true, amount: 0.3 });
  const [displayed, setDisplayed] = useState(0);
  useEffect(() => {
    if (!inView) return;
    const id = requestAnimationFrame(() => setDisplayed(activeCount));
    return () => cancelAnimationFrame(id);
  }, [inView, activeCount]);

  return (
    <div
      ref={setRefs}
      className={cn('flex flex-col gap-[var(--andromeda-2)]', className)}
      style={{ ...andromedaVars(), ...style }}
      {...props}
    >
      {label ? (
        <div className="flex items-baseline justify-between">
          <span className={labelClass}>{label}</span>
          <span className={valueClass}>{clamped}%</span>
        </div>
      ) : null}

      {/* Grid: BARS columns × SQUARES rows */}
      <div
        role="progressbar"
        aria-valuenow={clamped}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={typeof label === 'string' ? label : undefined}
        style={{
          display: 'flex',
          gap: `${GAP_COL}px`,
        }}
      >
        {Array.from({ length: BARS }, (_, barIndex) => {
          const active = barIndex < displayed;

          return (
            <div
              key={barIndex}
              style={{
                display: 'flex',
                flexDirection: 'column',
                gap: `${GAP_INNER}px`,
              }}
            >
              {Array.from({ length: SQUARES }, (_, sqIndex) => (
                <div
                  key={sqIndex}
                  style={{
                    width:  `${SQUARE_W}px`,
                    height: `${SQUARE_H}px`,
                    flexShrink: 0,
                    transform: 'skewX(-12deg)',
                    background: active
                      ? cfg.activeColor
                      : 'var(--andromeda-surface-overlay)',
                    border: `1px solid ${active ? cfg.activeBorder : 'var(--andromeda-border-subtle)'}`,
                    boxShadow: 'none',
                    transition: 'background 400ms ease, box-shadow 400ms ease, border-color 400ms ease',
                    transitionDelay: `${Math.floor(barIndex / 3) * 120}ms`,
                  }}
                />
              ))}
            </div>
          );
        })}
      </div>
    </div>
  );
});

export { variantConfig };

