// ── Default demo data ────────────────────────────────────────────────────────
const DEFAULT_DATA = [
  { axis: 'HULL',   nominal: 92, critical: 68 },
  { axis: 'POWER',  nominal: 78, critical: 45 },
  { axis: 'NAV',    nominal: 88, critical: 80 },
