// ============================================================
// COMPONENT: SegmentedControl
// shadcn/ui-aligned API: controlled `value` / `onChange`, options
// array, sized variants. A row of icon-or-label buttons with a
// `surface.active` fill that slides between segments via framer's
// `layoutId` — no manual measurement, no ResizeObserver, no raw
// timing strings. Token-driven duration + easing throughout.
// ============================================================

'use client';

import { forwardRef, useId } from 'react';
import { motion } from 'framer-motion';
import { cn, andromedaVars } from './lib/utils';
import { tokens } from '../tokens';

const SIZE_PX = {
  sm: 24,
  md: 32,
  lg: 40,
};

const ICON_PX = {
  sm: 14,
  md: 16,
  lg: 18,
};

const ms = (v) => parseInt(v, 10) / 1000;
// Inline cubic-bezier — framer wants arrays, tokens.motion.easing values are
// CSS strings. Keep in sync with tokens.motion.easing.standard.
const STANDARD_EASE = [0.4, 0, 0.2, 1];
const INDICATOR_TX = {
  duration: ms(tokens.motion.duration.slow),
  ease: STANDARD_EASE,
};

/**
 * @typedef {object} SegmentOption
 * @property {string} value
 * @property {string} [label]
 * @property {React.ComponentType<{ size?: number, weight?: string }>} [icon]
 * @property {string} [ariaLabel]
 */

/**
 * @typedef {object} SegmentedControlProps
 * @property {string} value
 * @property {(next: string) => void} onChange
 * @property {SegmentOption[]} options
 * @property {'sm'|'md'|'lg'} [size='md']
 * @property {string} [layoutGroupId]
 *   Override the auto-generated per-instance id only when you explicitly want
 *   two SegmentedControls to share their indicator (animating across both as
 *   one unit). The default `useId()` value scopes the indicator to a single
 *   control, which is what you want 99% of the time — without it, switching
 *   selections in one control makes the indicator fly between controls.
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<SegmentedControlProps & React.HTMLAttributes<HTMLDivElement>>} */
export const SegmentedControl = forwardRef(function SegmentedControl(
  { className, value, onChange, options, size = 'md', layoutGroupId, style, ...props },
  ref,
) {
  // Auto-scope the indicator's layoutId to this instance so multiple
  // SegmentedControls on the same page don't share the marker. Override
  // via `layoutGroupId` only when you explicitly want cross-instance
  // animation (rare).
  const generatedId = useId();
  const indicatorId = layoutGroupId ?? `andromeda-segmented-${generatedId}`;
  const cellSize = SIZE_PX[size] ?? SIZE_PX.md;
  const iconSize = ICON_PX[size] ?? ICON_PX.md;

  return (
    <div
      ref={ref}
      role="tablist"
      data-size={size}
      data-slot="segmented-control"
      className={cn('inline-flex relative select-none', className)}
      style={{
        ...andromedaVars(),
        height: `${cellSize}px`,
        border: `${tokens.border.thin} ${tokens.color.border.base}`,
        background: tokens.color.surface.raised,
        ...style,
      }}
      {...props}
    >
      {options.map((opt, i) => {
        const Icon = opt.icon;
        const active = opt.value === value;
        const showLabel = !Icon && opt.label;
        return (
          <button
            key={opt.value}
            type="button"
            role="tab"
            aria-selected={active}
            aria-label={opt.ariaLabel ?? opt.label}
            onClick={() => onChange(opt.value)}
            data-active={active}
            className="andromeda-segmented-item"
            style={{
              position: 'relative',
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: tokens.spacing[2],
              minWidth: showLabel ? undefined : `${cellSize}px`,
              height: '100%',
              padding: showLabel ? `0 ${tokens.spacing[3]}` : 0,
              background: 'transparent',
              border: 'none',
              borderLeft: i === 0 ? 'none' : `${tokens.border.thin} ${tokens.color.border.base}`,
              cursor: 'pointer',
              fontFamily: tokens.typography.fontMono,
              fontSize: tokens.typography.size.sm,
              fontWeight: active ? tokens.typography.weight.medium : tokens.typography.weight.regular,
              color: active ? tokens.color.text.primary : tokens.color.text.muted,
              textTransform: 'uppercase',
              letterSpacing: tokens.typography.tracking.wider,
              transition: `color ${tokens.motion.duration.normal} ${tokens.motion.easing.out}`,
            }}
          >
            {/* Sliding indicator — only the active button renders it.
                Framer's `layoutId` matches the new instance to the previous
                one and animates the layout change between siblings. */}
            {active ? (
              <motion.span
                layoutId={indicatorId}
                aria-hidden="true"
                transition={INDICATOR_TX}
                style={{
                  position: 'absolute',
                  inset: 0,
                  background: tokens.color.surface.active,
                  zIndex: 0,
                  pointerEvents: 'none',
                }}
              />
            ) : null}
            <span style={{ position: 'relative', zIndex: 1, display: 'inline-flex', alignItems: 'center', gap: tokens.spacing[2] }}>
              {Icon ? <Icon size={iconSize} weight="regular" /> : null}
              {opt.label && Icon ? <span>{opt.label}</span> : null}
              {showLabel ? opt.label : null}
            </span>
          </button>
        );
      })}

      {/* Hover styles — inline rule injected once per render scope.
          The :hover psuedo-class can't be expressed with React inline styles. */}
      <style>{`
        .andromeda-segmented-item:hover[data-active="false"] {
          color: ${tokens.color.text.primary};
        }
        .andromeda-segmented-item:focus-visible {
          outline: none;
          box-shadow: inset 0 0 0 1px ${tokens.color.accent[400]};
        }
      `}</style>
    </div>
  );
});

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Slider
// shadcn/ui-aligned API: forwardRef, controlled (`value`) /
// uncontrolled (`defaultValue`), onValueChange. Single-value
// horizontal range slider with a sharp rectangular thumb and
// a glowing accent fill — sci-fi telemetry vibe.
//
// Built without a native <input type="range"> so the chrome
// is fully consistent across browsers. ARIA-compliant via
// role="slider" + aria-valuenow/min/max.
// ============================================================

'use client';

import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useRef,
  useState,
} from 'react';
import { cn, andromedaVars } from './lib/utils';

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function snap(n, step) {
  if (!step || step <= 0) return n;
  return Math.round(n / step) * step;
}

/**
 * @typedef {object} SliderProps
 * @property {number} [value]                  Controlled value.
 * @property {number} [defaultValue]           Uncontrolled initial value.
 * @property {number} [min=0]
 * @property {number} [max=100]
 * @property {number} [step=1]
 * @property {(next: number) => void} [onValueChange]
 * @property {string} [label]                  Optional uppercase mono label.
 * @property {boolean} [showValue=true]        Render the numeric readout next to the label.
 * @property {string} [unit]                   Optional unit suffix (e.g. "%", "KM").
 * @property {boolean} [disabled]
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 * @property {string} [id]
 */

/** @type {React.ForwardRefExoticComponent<SliderProps & Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'>>} */
export const Slider = forwardRef(function Slider(
  {
    className,
    value: controlledValue,
    defaultValue,
    min = 0,
    max = 100,
    step = 1,
    onValueChange,
    label,
    showValue = true,
    unit,
    disabled = false,
    id: idProp,
    style,
    ...props
  },
  ref,
) {
  const reactId = useId();
  const id = idProp ?? `andromeda-slider-${reactId}`;
  const isControlled = controlledValue !== undefined;
  const [internal, setInternal] = useState(
    defaultValue ?? min,
  );
  const value = clamp(isControlled ? controlledValue : internal, min, max);

  const trackRef = useRef(/** @type {HTMLDivElement|null} */ (null));
  const draggingRef = useRef(false);

  const setValue = useCallback(
    (next) => {
      const snapped = clamp(snap(next, step), min, max);
      if (snapped === value) return;
      if (!isControlled) setInternal(snapped);
      onValueChange?.(snapped);
    },
    [isControlled, max, min, onValueChange, step, value],
  );

  const valueFromClientX = useCallback(
    (clientX) => {
      const track = trackRef.current;
      if (!track) return value;
      const rect = track.getBoundingClientRect();
      const ratio = clamp((clientX - rect.left) / rect.width, 0, 1);
      return min + ratio * (max - min);
    },
    [max, min, value],
  );

  // ── Pointer drag (mouse + touch unified) ─────────────────────────────────
  useEffect(() => {
    if (disabled) return undefined;

    const onPointerMove = (e) => {
      if (!draggingRef.current) return;
      setValue(valueFromClientX(e.clientX));
    };
    const onPointerUp = () => {
      draggingRef.current = false;
    };

    window.addEventListener('pointermove', onPointerMove);
    window.addEventListener('pointerup', onPointerUp);
    window.addEventListener('pointercancel', onPointerUp);
    return () => {
      window.removeEventListener('pointermove', onPointerMove);
      window.removeEventListener('pointerup', onPointerUp);
      window.removeEventListener('pointercancel', onPointerUp);
    };
  }, [disabled, setValue, valueFromClientX]);

  function handlePointerDown(e) {
    if (disabled) return;
    e.currentTarget.setPointerCapture?.(e.pointerId);
    draggingRef.current = true;
    setValue(valueFromClientX(e.clientX));
  }

  function handleKeyDown(e) {
    if (disabled) return;
    const big = (max - min) / 10;
    switch (e.key) {
      case 'ArrowLeft':
      case 'ArrowDown':
        e.preventDefault();
        setValue(value - step);
        break;
      case 'ArrowRight':
      case 'ArrowUp':
        e.preventDefault();
        setValue(value + step);
        break;
      case 'PageDown':
        e.preventDefault();
        setValue(value - big);
        break;
      case 'PageUp':
        e.preventDefault();
        setValue(value + big);
        break;
      case 'Home':
        e.preventDefault();
        setValue(min);
        break;
      case 'End':
        e.preventDefault();
        setValue(max);
        break;
      default:
        break;
    }
  }

  const percent = ((value - min) / (max - min)) * 100;

  return (
    <div
      ref={ref}
      className={cn('flex flex-col gap-[var(--andromeda-2)]', className)}
      style={{ ...andromedaVars(), ...style }}
      {...props}
    >
      {(label || showValue) ? (
        <div className="flex items-baseline justify-between">
          {label ? (
            <span
              className={cn(
                '[font-family:var(--andromeda-font-mono)]',
                'text-[length:var(--andromeda-text-xs)]',
                'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
                'text-[color:var(--andromeda-text-secondary)]',
              )}
            >
              {label}
            </span>
          ) : <span />}
          {showValue ? (
            <span
              className={cn(
                '[font-family:var(--andromeda-font-mono)]',
                'text-[length:var(--andromeda-text-xs)]',
                'font-[number:var(--andromeda-weight-medium)]',
                'uppercase [letter-spacing:var(--andromeda-tracking-wider)]',
                'text-[color:var(--andromeda-text-primary)]',
              )}
            >
              {Number.isInteger(step) ? Math.round(value) : value.toFixed(2)}
              {unit ?? ''}
            </span>
          ) : null}
        </div>
      ) : null}

      {/* Track */}
      <div
        ref={trackRef}
        id={id}
        role="slider"
        tabIndex={disabled ? -1 : 0}
        aria-valuemin={min}
        aria-valuemax={max}
        aria-valuenow={value}
        aria-label={typeof label === 'string' ? label : undefined}
        aria-disabled={disabled || undefined}
        onPointerDown={handlePointerDown}
        onKeyDown={handleKeyDown}
        className={cn(
          'relative h-[18px] w-full select-none touch-none',
          'cursor-pointer',
          disabled && 'opacity-[0.4] cursor-not-allowed pointer-events-none',
          'focus-visible:outline-none',
          'focus-visible:[--slider-thumb-shadow:0_0_0_1px_var(--andromeda-accent-100),0_0_10px_var(--andromeda-accent-500)]',
        )}
      >
        {/* Track line */}
        <div
          className={cn(
            'absolute left-0 right-0 top-1/2 -translate-y-1/2',
            'h-[3px] border border-solid',
            'bg-[color:var(--andromeda-surface-overlay)]',
            'border-[color:var(--andromeda-border-subtle)]',
          )}
        />
        {/* Filled portion */}
        <div
          className={cn(
            'absolute left-0 top-1/2 -translate-y-1/2 h-[3px]',
            '[background:linear-gradient(90deg,var(--andromeda-accent-400)_0%,var(--andromeda-accent-300)_100%)]',
            'shadow-[0_0_8px_var(--andromeda-accent-500)]',
          )}
          style={{ width: `${percent}%` }}
        />
        {/* Thumb */}
        <div
          aria-hidden="true"
          className={cn(
            'absolute top-1/2 -translate-y-1/2 -translate-x-1/2',
            'w-[8px] h-[16px]',
            'bg-[color:var(--andromeda-accent-300)]',
            'border border-solid border-[color:var(--andromeda-accent-100)]',
            'shadow-[var(--slider-thumb-shadow,0_0_8px_var(--andromeda-accent-500))]',
            'transition-[box-shadow,transform] duration-150 ease-out',
            'hover:scale-[1.25]',
          )}
          style={{ left: `${percent}%` }}
        />
      </div>
    </div>
  );
});

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: Spinner
// 3×3 grid of square pixels with a "snake game" trail running
// clockwise around the perimeter. The 8 perimeter cells share a
// single keyframe; each cell's animation-delay is negative so all
// cells run on phase from the moment the spinner mounts. The
// center cell stays as a static dim square. Variants only colour
// the bright phase — the dim phase is always `text.faint`.
//
// Variants: default | accent | warning | fault
// Sizes:    sm (14px) | md (20px) | lg (28px)
// ============================================================

'use client';

import { forwardRef, useEffect } from 'react';
import { tokens } from '../tokens';
import { andromedaVars } from './lib/utils';

const STYLE_ID = 'andromeda-spinner-keyframes';
// 0-37.5% bright, 37.5-100% dim. The 37.6% stop snaps the colour change so
// the trail moves like discrete LCD pixels instead of fading. Over 1.2 ms
// of cycle the linear interpolation is imperceptible — it just looks crisp.
const KEYFRAMES = `
  @keyframes andromeda-spinner-snake {
    0%, 37.5%   { background: var(--andromeda-spinner-bright); }
    37.6%, 100% { background: var(--andromeda-spinner-dim); }
  }
`;

function ensureKeyframesInjected() {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = KEYFRAMES;
  document.head.appendChild(style);
}

const SIZE_MAP = {
  sm: { wrap: 14, cell: 4, gap: 1 },
  md: { wrap: 20, cell: 6, gap: 1 },
  lg: { wrap: 28, cell: 8, gap: 2 },
};

const colorByVariant = {
  default: tokens.color.text.primary,
  accent:  tokens.color.accent[300],
  warning: tokens.color.orange[300],
  fault:   tokens.color.red[300],
};

// Clockwise perimeter starting top-left. Center cell (1,1) is intentionally
// excluded — it stays statically dim like a snake-game arena interior.
const PERIMETER_ORDER = [
  [0, 0], [0, 1], [0, 2],
  [1, 2],
  [2, 2], [2, 1], [2, 0],
  [1, 0],
];

const DURATION_MS = 1200;
const STEPS = 8;
const STEP_MS = DURATION_MS / STEPS;

/**
 * @typedef {object} SpinnerProps
 * @property {'default'|'accent'|'warning'|'fault'} [variant='default']
 * @property {'sm'|'md'|'lg'} [size='md']
 * @property {string} [label='Loading'] Accessible label.
 * @property {string} [className]
 * @property {React.CSSProperties} [style]
 */

/** @type {React.ForwardRefExoticComponent<SpinnerProps & React.HTMLAttributes<HTMLSpanElement>>} */
export const Spinner = forwardRef(function Spinner(
  { className, variant = 'default', size = 'md', label = 'Loading', style, ...props },
  ref,
) {
  useEffect(() => { ensureKeyframesInjected(); }, []);
  ensureKeyframesInjected();

  const sz = SIZE_MAP[size] ?? SIZE_MAP.md;
  const bright = colorByVariant[variant] ?? colorByVariant.default;
  const dim = tokens.color.text.faint;

  const cells = [];
  for (let r = 0; r < 3; r++) {
    for (let c = 0; c < 3; c++) {
      const peri = PERIMETER_ORDER.findIndex(([pr, pc]) => pr === r && pc === c);
      const isCenter = peri === -1;
      // delay = -((STEPS - peri) % STEPS) * step — at t=0 cell `peri` is at
      // (peri/STEPS) of its cycle. peri=0 starts bright; the trail extends
      // backward from there (cells 7 and 6 are still inside the bright window).
      const delayMs = isCenter ? 0 : -((STEPS - peri) % STEPS) * STEP_MS;
      cells.push(
        <span
          key={`${r}-${c}`}
          aria-hidden
          style={{
            width:  `${sz.cell}px`,
            height: `${sz.cell}px`,
            background: dim,
            ...(isCenter ? null : {
              animation: `andromeda-spinner-snake ${DURATION_MS}ms linear infinite`,
              animationDelay: `${delayMs}ms`,
            }),
          }}
        />,
      );
    }
  }

  return (
    <span
      ref={ref}
      role="status"
      aria-label={label}
      className={className}
      style={{
        ...andromedaVars(),
        '--andromeda-spinner-bright': bright,
        '--andromeda-spinner-dim': dim,
        display: 'inline-grid',
        gridTemplateColumns: `repeat(3, ${sz.cell}px)`,
        gridTemplateRows: `repeat(3, ${sz.cell}px)`,
        gap: `${sz.gap}px`,
        width:  `${sz.wrap}px`,
        height: `${sz.wrap}px`,
        ...style,
      }}
      {...props}
    >
      {cells}
    </span>
  );
});

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// COMPONENT: StatTile
// shadcn/ui-aligned API: forwardRef, className passthrough.
// Telemetry-style readout built on the Card primitive.
//
//  ┌── label (mono, text.secondary, tracking.wide) ── code ─┐
//  │  BIG NUMBER (sans, text.primary, size.4xl)   unit      │
//  ├────────────────────────────────────────────────────────┤
//  │  ▲/▼ delta (accent on +, fault on −)   delta label     │
//  └────────────────────────────────────────────────────────┘
//
// Animations:
//  - Value counts up from 0 on mount (easeOutExpo, 1.8s)
//  - Delta arrow flickers randomly (signal-loss glitch)
//  - Scanline sweeps down on mount (terminal boot)
// ============================================================

'use client';

import { forwardRef, useEffect, useRef, useState } from 'react'; // useRef kept for useCountUp's RAF tracking
import { useInView, AnimatePresence, motion } from 'framer-motion';
import { cn, andromedaVars } from './lib/utils';
import { useReducedMotion } from './lib/motion';
import { tokens } from '../tokens';
import { Card, CardContent } from './Card';

const ms = (v) => parseInt(v, 10) / 1000;
// Inline cubic-beziers — framer wants arrays, tokens.motion.easing values are
// CSS strings. Keep these in sync with tokens.motion.easing.sharp.
const SHARP_EASE = [0.4, 0, 0.6, 1];

// ── DigitRoller ──────────────────────────────────────────────────────────────
// Renders a number/string as a row of fixed-width slots; when the value
// changes, only the slots whose character changed roll. Built on framer's
// AnimatePresence per slot — the key is the character, so a stable digit
// stays put while a changed digit gets exit+enter.
//
// Width per slot is `1ch`, paired with `font-variant-numeric: tabular-nums`
// so digits and punctuation align in a column. Sans-serif punctuation can
// be slightly narrower than 1ch but tabular-nums makes digits match exactly.
function DigitSlot({ char, reduced }) {
  if (reduced) {
    return <span style={{ display: 'inline-block' }}>{char}</span>;
  }
  return (
    <span
      style={{
        position: 'relative',
        display: 'inline-block',
        width: '1ch',
        height: '1em',
        overflow: 'hidden',
        verticalAlign: 'baseline',
      }}
    >
      <AnimatePresence initial={false} mode="popLayout">
        <motion.span
          key={char}
          initial={{ y: '100%', opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: '-100%', opacity: 0 }}
          transition={{ duration: ms(tokens.motion.duration.normal), ease: SHARP_EASE }}
          style={{
            position: 'absolute',
            inset: 0,
            display: 'inline-flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {char}
        </motion.span>
      </AnimatePresence>
    </span>
  );
}

function DigitRoller({ value, className, reduced }) {
  const chars = String(value).split('');
  return (
    <span
      className={className}
      style={{
        fontVariantNumeric: 'tabular-nums',
        display: 'inline-flex',
        alignItems: 'baseline',
      }}
    >
      {chars.map((c, i) => (
        // Index-based key — a "slot" stays at position i across renders.
        // The DigitSlot's inner AnimatePresence uses the character itself
        // as its key so position-stable but character-changed slots roll.
        <DigitSlot key={i} char={c} reduced={reduced} />
      ))}
    </span>
  );
}

// ── Styles injected once ─────────────────────────────────────────────────────
function useStatTileStyles() {
  useEffect(() => {
    if (document.querySelector('#andromeda-stat-tile-style')) return;
    const style = document.createElement('style');
    style.id = 'andromeda-stat-tile-style';
    style.textContent = `
      @keyframes andromeda-value-in {
        from { opacity: 0; transform: translateY(4px); }
        to   { opacity: 1; transform: translateY(0); }
      }
    `;
    document.head.appendChild(style);
  }, []);
}

// ── easeOutExpo ──────────────────────────────────────────────────────────────
function easeOutExpo(t) {
  return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
}

// ── useCountUp ───────────────────────────────────────────────────────────────
// Animates from 0 → target over `duration` ms when the tile first enters
// the viewport (scroll-aware). Returns the display string, preserving the
// original decimal precision of `rawValue`.
//
// `live=true` switches behaviour: count-up still runs once on first
// view-entry (the reveal moment), but subsequent prop updates snap to
// the new value without re-running the animation. This is the Andromeda
// rule — state changes (data updates) are instant or ~80ms; never longer.
// Telemetry rows that update every couple of seconds would otherwise
// spasm a 1.8s count-up FROM ZERO on every refresh.
//
// Scroll-awareness: pre-mount the count-up doesn't fire. The provided
// `inView` flag (true once the parent tile is visible in the viewport)
// gates the animation so tiles below the fold don't burn their reveal
// off-screen. Templates with multi-screen height get the count-up at
// the moment the user actually sees the value.
function useCountUp(rawValue, duration = 1800, live = false, inView = true) {
  const num = parseFloat(rawValue);
  const isNumeric = !isNaN(num);
  const decimals = isNumeric
    ? (String(rawValue).split('.')[1] ?? '').length
    : 0;

  const [display, setDisplay] = useState(isNumeric ? '0' : rawValue);
  const rafRef = useRef(null);
  const startRef = useRef(null);
  const hasMountedRef = useRef(false);

  useEffect(() => {
    if (!isNumeric) { setDisplay(rawValue); return; }

    // After first reveal, in `live` mode, snap to the new value without
    // animating. Live data updates are signal, not a chance to re-reveal.
    if (live && hasMountedRef.current) {
      setDisplay(decimals > 0 ? num.toFixed(decimals) : String(Math.round(num)));
      return;
    }

    // Wait for the tile to enter the viewport before kicking off the
    // count-up. Tiles above the fold see this as `true` immediately;
    // tiles below the fold wait until scrolled to.
    if (!inView) return;

    // First reveal: run the count-up. Small delay so the card's outer
    // entrance (cascade slide-in) is visible first, then the value tweens.
    const timeout = setTimeout(() => {
      startRef.current = null;

      function tick(now) {
        if (!startRef.current) startRef.current = now;
        const elapsed = now - startRef.current;
        const t = Math.min(elapsed / duration, 1);
        const current = num * easeOutExpo(t);
        setDisplay(decimals > 0 ? current.toFixed(decimals) : String(Math.round(current)));
        if (t < 1) rafRef.current = requestAnimationFrame(tick);
        else hasMountedRef.current = true;
      }

      rafRef.current = requestAnimationFrame(tick);
    }, 120);

    return () => {
      clearTimeout(timeout);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rawValue, inView]);

  return display;
}


