const EASE_STANDARD = [0.4, 0, 0.2, 1]; // tokens.motion.easing.standard

/**
 * @typedef {object} UserCardProps
 * @property {string} name
 * @property {string} [role]           Subtitle under the name (e.g. "Flight Director").
 * @property {string} [src]
